#include<stdio.h>
#include<string.h>
#include<ctype.h>
int main(){
    char s[101];
    scanf("%s",s);
    int cnt1=0,cnt2=0;
    for(int i=0;i<strlen(s);i++){
        if(islower(s[i])){
            cnt1++;
        }else{
            cnt2++;
        }
    }for(int i=0;i<strlen(s);i++){
        if(cnt1>=cnt2){
            s[i]=tolower(s[i]);
        }else if(cnt1<cnt2){
            s[i]=toupper(s[i]);
        }
    }
    printf("%s",s);
    return 0;

}

